con:config.script:
// 1. Lista GIGANTE de países (Majesco es global, ¡metamos más!)
def countryCodes = ["in", "io", "us", "co", "mx", "ca", "gb", "br", "ar", "es", "fr", "de", "it", "jp", "au", "kr", "cl", "pe", "pa", "uy"]

// 2. Traer la "Memoria" de la Suite (donde guardamos los últimos usados)
def memoria = testRunner.testCase.testSuite.getPropertyValue("HistorialPaises") ?: ""
def listaMemoria = memoria.split(",") as List

def randomCode = ""
def intentos = 0

// 3. Lógica de "No Repetición" (Intentar hasta 10 veces buscar uno nuevo)
while (intentos < 10) {
    randomCode = countryCodes[new Random().nextInt(countryCodes.size())]
    if (!listaMemoria.contains(randomCode)) {
        break // ¡Encontramos uno que no se ha usado recientemente!
    }
    intentos++
}

// 4. Actualizar la Memoria (Guardar los últimos 6 para que no se repitan)
listaMemoria.add(0, randomCode) // Lo metemos al principio
if (listaMemoria.size() > 6) {
    listaMemoria = listaMemoria.take(6) // Solo recordamos los últimos 6
}
testRunner.testCase.testSuite.setPropertyValue("HistorialPaises", listaMemoria.join(","))

// 5. Inyectar al TestCase
testRunner.testCase.setPropertyValue("TargetCountry", randomCode)

log.info "--- Majesco Smart Generator ---"
log.info "País seleccionado: ${randomCode.toUpperCase()}"
log.info "Memoria actual (No repetir): ${listaMemoria}"

con:configuration.scriptText:
import groovy.json.JsonSlurper def json = new JsonSlurper().parseText(messageExchange.responseContent)[0]
// 1. Extraer dinámicamente la primera moneda del objeto 'currencies' def currencyKey = json.currencies.keySet()[0] def currencyData = json.currencies."${currencyKey}"
log.info "--- Validando Moneda para el país: ${json.name.common} ---" log.info "Código detectado: ${currencyKey} | Nombre: ${currencyData.name}"
// Assertions Dinámicos assert currencyKey != null : "❌ Error: El código de moneda (ISO) es nulo." assert currencyData.name != null : "❌ Error: La moneda no tiene un nombre definido." assert currencyData.symbol != null : "❌ Error: Falta el símbolo de moneda para reportes financieros."

import groovy.json.JsonSlurper
def json = new JsonSlurper().parseText(messageExchange.responseContent)[0]

log.info "--- Validando Reglas de Dirección (Postal Code) ---"

// Validamos si el país exige formato postal en el Core
if (json.postalCode != null) {
    def format = json.postalCode.format
    def regex = json.postalCode.regex

    log.info "País con reglas postales: Formato [${format}]"
    assert format != null : "❌ Error: El formato postal existe pero está vacío."
} else {
    log.info "País sin reglas postales obligatorias (Acepta texto libre)."
}

import groovy.json.JsonSlurper
def json = new JsonSlurper().parseText(messageExchange.responseContent)[0]

def poblacion = json.population
def nombrePais = json.name.common

log.info "--- Validando Análisis de Riesgo ---"
log.info "Población de ${nombrePais}: ${poblacion}"

// Regla de Negocio: Si el país es independiente, debe tener población para ser asegurable
if (json.independent == true) {
    assert poblacion > 0 : "❌ Error de Riesgo: ${nombrePais} es independiente pero reporta 0 habitantes. Datos inconsistentes para el Core."
} else {
    log.info "Territorio no independiente. Se permite población baja o cero bajo reglas especiales."
}

import groovy.json.JsonSlurper
def json = new JsonSlurper().parseText(messageExchange.responseContent)[0]

def region = json.region
def moneda = json.currencies.keySet()[0]

log.info "Validando Consistencia: Region [${region}] vs Moneda [${moneda}]"

// Regla de Negocio: Si la región es Americas, la moneda no puede ser JPY (Yen)
if (region == "Americas") {
    assert moneda != "JPY" : "❌ Error de Consistencia: Un país en Americas no puede tener Yen como moneda principal en el Core."
}
log.info "✅ Consistencia regional validada."

import groovy.json.JsonSlurper def json = new JsonSlurper().parseText(messageExchange.responseContent)[0]
def sufijos = json.idd.suffixes
log.info "Validando lista de prefijos telefónicos (IDD Suffixes)..."
// 1. Validar que la lista de sufijos exista y tenga al menos un elemento assert sufijos instanceof List : "❌ Error: Suffixes debería ser una lista (Array)." assert sufijos.size() > 0 : "❌ Error: El país debe tener al menos un sufijo telefónico para contacto."
// 2. Validar que el primer sufijo sea un número (en formato String) assert sufijos[0].isNumber() : "❌ Error: El sufijo [${sufijos[0]}] no es un valor numérico válido."
log.info "✅ Estructura de listas anidadas validada (Total: ${sufijos.size()} prefijos)."

import groovy.json.JsonSlurper
def json = new JsonSlurper().parseText(messageExchange.responseContent)[0]

def pop = json.population

log.info "Analizando Segmentación de Mercado para: " + json.name.common

if (pop > 100000000) { // Mas de 100 Millones
    log.info "Mercado de Alto Volumen detectado."
    // Regla: Mercados grandes DEBEN tener un link de bandera PNG válido
    assert json.flags.png.contains("http") : "❌ Error: País de alto volumen sin recurso visual (Flag PNG) en el Core."
} else {
    log.info "Mercado de Volumen Estándar."
}

import groovy.json.JsonSlurper
def json = new JsonSlurper().parseText(messageExchange.responseContent)[0]

def poblacion = json.population
def nombre = json.name.common

log.info "--- Analizando Riesgo de Mercado: ${nombre} ---"

if (poblacion > 40000000) {
    log.info "⚠️ ALERTA DE RIESGO: Población masiva detectada (${poblacion})."
    // En Majesco, esto activaría una regla de 'High Exposure'
    assert json.status == "officially-assigned" : "Error: Mercados de alto riesgo deben estar plenamente regulados."
} else {
    log.info "Mercado de riesgo controlado."
}

import groovy.json.JsonSlurper
def json = new JsonSlurper().parseText(messageExchange.responseContent)[0]

// Supongamos que el índice 'Gini' representa la 'Complejidad del Riesgo' (como la edad)
if (json.gini != null) {
    def valorRiesgo = json.gini.values()[0] // Tomamos el primer valor del mapa Gini
    log.info "Índice de Complejidad detectado: ${valorRiesgo}"

    if (valorRiesgo > 40) {
        log.info "🛑 REQUIERE REVISIÓN MANUAL: Riesgo excede los límites automáticos."
        // Validamos que el sistema tenga cargada la información de contacto (Capital) para auditoría
        assert json.capital[0] != null : "Error: Datos de contacto obligatorios para riesgos complejos."
    }
}

import groovy.json.JsonSlurper
def json = new JsonSlurper().parseText(messageExchange.responseContent)[0]

def area = json.area
def poblacion = json.population
def nombre = json.name.common

log.info "--- Evaluando Perfil Agro-Sostenible: ${nombre} ---"

// Calculamos la Densidad (Personas por km2)
def densidad = poblacion / area

if (area > 500000 && densidad < 50) {
    log.info "✅ PERFIL VERDE: País con alta capacidad de sostenibilidad y agricultura."
    // En Majesco: Aplicar "Sustainability Discount"
    assert json.landlocked == false : "Error: Para exportación agraria masiva, el acceso al mar es preferible."
} else if (area < 50000 && densidad > 200) {
    log.info "⚠️ RIESGO DE IMPORTACIÓN: Alta densidad, poca tierra. Requiere cláusula de suministro."
    // En Majesco: Activar "Dependency Surcharge"
    assert json.status == "officially-assigned" : "Error: Países con crisis potencial deben estar bajo estatus legal estricto."
}
